// Detect Message Type + Extract file_id + caption/text
const msg = $('Telegram Trigger').first().json.message;
const chatId = msg.chat.id;

let fileType = 'text';
let fileId = '';
let userMessage = '';
let mimeType = '';

if (msg.photo && msg.photo.length > 0) {
  fileType = 'image';
  // Last element = highest resolution
  fileId = msg.photo[msg.photo.length - 1].file_id;
  userMessage = msg.caption || '(foto enviada sem pergunta — analisa o conteudo da imagem)';
} else if (msg.document) {
  fileType = 'document';
  fileId = msg.document.file_id;
  mimeType = msg.document.mime_type || '';
  userMessage = msg.caption || '(documento enviado sem pergunta — analisa o conteudo)';
} else if (msg.voice) {
  fileType = 'audio';
  fileId = msg.voice.file_id;
  mimeType = msg.voice.mime_type || 'audio/ogg';
  userMessage = '(audio — aguardando transcricao)';
} else if (msg.audio) {
  fileType = 'audio';
  fileId = msg.audio.file_id;
  mimeType = msg.audio.mime_type || 'audio/mpeg';
  userMessage = '(audio — aguardando transcricao)';
} else if (msg.text) {
  fileType = 'text';
  userMessage = msg.text;
} else {
  fileType = 'text';
  userMessage = '(tipo de mensagem nao suportado)';
}

// Student context
let studentName = '';
let studentContext = '';

if (chatId === 8743894892) {
  studentName = 'Giuliana Fiamenghi Ribeiro';
  studentContext = 'Giuliana tem 21 anos, estuda Biomedicina. Lingua preferida: PT-BR. Trata-a como uma jovem adulta universitaria inteligente e curiosa.';
} else if (chatId === 8523053691) {
  studentName = 'Maria Vitoria Fiamenghi Ribeiro';
  studentContext = 'Maria Vitoria tem 23 anos. Lingua preferida: PT-BR. Trata-a como uma jovem adulta universitaria inteligente e curiosa.';
}

return [{ json: {
  fileType,
  fileId,
  userMessage,
  mimeType,
  studentName,
  studentContext,
  chatId: String(chatId)
} }];

// After Whisper transcription — set userMessage to transcribed text
const transcription = $input.first().json.text || '(nao foi possivel transcrever o audio)';
const detect = $('Detect Message Type').first().json;

return [{ json: {
  ...detect,
  userMessage: transcription,
  fileType: 'audio',
  fileContent: '',
  fileDescription: ''
} }];

// Process image or document via Haiku Vision API
const detect = $('Detect Message Type').first().json;
const binaryData = $input.first().binary;

if (!binaryData || !binaryData.data) {
  return [{ json: { ...detect, fileContent: '', fileDescription: '(erro ao processar ficheiro)' } }];
}

const base64 = binaryData.data.data;
let fileMimeType = binaryData.data.mimeType || detect.mimeType || '';
const validImageTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
const validDocTypes = ['application/pdf'];
if (detect.fileType === 'image' && !validImageTypes.includes(fileMimeType)) {
  fileMimeType = 'image/jpeg';
} else if (detect.fileType === 'document' && !validDocTypes.includes(fileMimeType)) {
  fileMimeType = 'application/pdf';
}
const fileType = detect.fileType;

let content = [];

if (fileType === 'image') {
  content = [
    {
      type: 'image',
      source: {
        type: 'base64',
        media_type: fileMimeType,
        data: base64
      }
    },
    {
      type: 'text',
      text: 'Descreve detalhadamente o conteudo desta imagem. Se for um exercicio escolar, transcreve o enunciado completo e identifica a disciplina. Se for texto manuscrito, transcreve-o. Se for um diagrama ou grafico, descreve-o. Responde em portugues.'
    }
  ];
} else if (fileType === 'document') {
  // PDF via document type
  content = [
    {
      type: 'document',
      source: {
        type: 'base64',
        media_type: fileMimeType.includes('pdf') ? 'application/pdf' : fileMimeType,
        data: base64
      }
    },
    {
      type: 'text',
      text: 'Extrai e resume o conteudo principal deste documento. Se forem apontamentos ou exercicios, identifica a disciplina e os topicos. Transcreve partes relevantes. Maximo 1000 palavras. Responde em portugues.'
    }
  ];
}

const body = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 2048,
  messages: [{ role: 'user', content: content }]
};

return [{ json: {
  body: JSON.stringify(body),
  studentName: detect.studentName,
  studentContext: detect.studentContext,
  userMessage: detect.userMessage,
  chatId: detect.chatId,
  fileType: detect.fileType,
  mimeType: detect.mimeType
} }];

// Parse Haiku Vision response and merge back with context
const visionResponse = $input.first().json;
const prepData = $('Prepare Vision Request').first().json;

let fileDescription = '';
try {
  fileDescription = visionResponse.content[0].text || '';
} catch(e) {
  fileDescription = '(erro ao analisar ficheiro)';
}

return [{ json: {
  studentName: prepData.studentName,
  studentContext: prepData.studentContext,
  userMessage: prepData.userMessage,
  chatId: prepData.chatId,
  fileType: prepData.fileType,
  fileContent: '',
  fileDescription: fileDescription
} }];

// Text-only path — no file processing needed
