return [{ json: {
  studentName: detect.studentName,
  studentContext: detect.studentContext,
  userMessage: detect.userMessage,
  chatId: detect.chatId,
  fileType: 'text',
  fileContent: '',
  fileDescription: ''
} }];

// Merge node — receives from 3 paths: text, audio, image/document
const item = $input.first().json;

return [{ json: {
  studentName: item.studentName,
  studentContext: item.studentContext,
  userMessage: item.userMessage,
  chatId: item.chatId,
  fileType: item.fileType,
  fileContent: item.fileContent || '',
  fileDescription: item.fileDescription || ''
} }];

const allItems = $items('Get Recent History');
const summaryItems = $('Get Rolling Summary').all();

const ctx = $('Merge Context').first().json;
const studentName = ctx.studentName;
const studentContext = ctx.studentContext;
const userMessage = ctx.userMessage;
const chatId = ctx.chatId;
const fileType = ctx.fileType;
const fileDescription = ctx.fileDescription || '';

let rollingSummary = '';
if (summaryItems && summaryItems.length > 0) {
  const f = summaryItems[0].json.fields || summaryItems[0].json;
  if (f.Details) {
    rollingSummary = `\n\nMEMORIA DE LONGO PRAZO (resumo de todas as conversas anteriores):\n${f.Details}`;
  }
}

const historyItems = $('Get Recent History').all();
let historyText = '';
let messageCount = 0;
if (historyItems && historyItems.length > 0) {
  const msgs = historyItems
    .map(i => {
      const f = i.json.fields || i.json;
      if (!f.Message) return null;
      messageCount++;
      const role = f.Role === 'assistant' ? 'Tutor' : f.Name || 'Aluna';
      return `${role}: ${f.Message.substring(0, 300)}`;
    })
    .filter(Boolean)
    .reverse()
    .slice(-10);
  if (msgs.length > 0) {
    historyText = `\n\nHISTORICO RECENTE (ultimas mensagens):\n${msgs.join('\n')}`;
  }
}

// Build file context section
let fileContext = '';
if (fileType === 'image' && fileDescription) {
  fileContext = `\n\nCONTEUDO DO FICHEIRO ENVIADO (imagem analisada por IA):\n${fileDescription}\n\nA estudante enviou uma foto. Usa a descricao acima para entender o conteudo e ajuda-la. Se for um exercicio, guia-a pelo metodo Socratico sem dar a resposta directa.`;
} else if (fileType === 'document' && fileDescription) {
  fileContext = `\n\nCONTEUDO DO DOCUMENTO ENVIADO (extraido por IA):\n${fileDescription}\n\nA estudante enviou um documento. Usa o conteudo extraido acima para ajuda-la. Se forem apontamentos, oferece-te para explicar ou fazer perguntas de revisao.`;
} else if (fileType === 'audio') {
  fileContext = `\n\nNOTA: A estudante enviou uma mensagem de audio que foi transcrita automaticamente. A pergunta abaixo e a transcricao do audio.`;
}

const prompt = `Es um tutor pessoal chamado Tutor IA para ${studentName}. ${studentContext}${rollingSummary}${historyText}${fileContext}

REGRAS:
1. Explica de forma clara e adequada a idade da estudante
2. Usa exemplos praticos e do dia a dia
3. Se a pergunta envolver conteudo perigoso, inapropriado ou para adultos, recusa educadamente
4. Se a pergunta for sobre um exercicio ou exame, NAO des a resposta directa. Guia a estudante com perguntas e dicas para que ela chegue a resposta sozinha (metodo Socratico)
5. Se nao sabes a resposta, diz honestamente
6. Responde no mesmo idioma em que a pergunta foi feita
7. Se for uma pergunta de matematica ou ciencias, mostra o raciocinio passo a passo
8. Se a pergunta for conversa casual (ola, tudo bem, etc), responde de forma amigavel e natural
9. Usa a MEMORIA DE LONGO PRAZO para continuidade — se a aluna ja estudou um tema antes, referencia isso naturalmente
10. Maximo 500 palavras na resposta
11. Se a aluna enviou uma foto ou documento, analisa o conteudo descrito e responde em contexto
12. Se a aluna enviou audio, responde normalmente a pergunta transcrita

PERGUNTA DA ESTUDANTE:
${userMessage}`;

return [{ json: { prompt, timeout: 60000, chatId, studentName, userMessage, messageCount, fileType } }];

